-void shared_create(
-    SharedData* data,
-    const char* name,
-    void* bytes,
-    size_t nbytes) {
-  int d = shm_open(name, O_CREAT | O_RDWR, S_IRUSR | S_IWUSR);
-  if (d != -1) {
-    if (nbytes = write(d, bytes, nbytes)) {
-      shared_open(data, name, nbytes);
-    }
-    close(d);
-  } else {
-    printf("shared_create %s failed\n", name);
-  }
-}
