-void reduce_all_buffers(
-    int start_elements,
-    int num_elements,
-    int element_size,
-    int to_buffer_idx,
-    int world_size,
-    char* to_buffer,
-    char** buffers,
-    ReductionFunction fn) {
-  size_t offset = start_elements * element_size;
-  memcpy(to_buffer + offset, buffers[0] + offset, num_elements * element_size);
-  for (int i = 1; i < world_size; i++) {
-    fn(to_buffer + offset,
-       to_buffer + offset,
-       buffers[i] + offset,
-       num_elements);
-  }
-}
