+    char name[NAME_BUF_SIZE];
+    char buffer[2 * NAIVE_ALLREDUCE_THRESHOLD + 2 * MAX_BUF_SIZE];
+  };
+
+  AllreduceSharedMemoryData(int rank, int world_size)
+      : rank(rank),
+        world_size(world_size),
+        current_buffer(0),
+        state_idx(0),
+        is_initialized(false) {}
