+#define UV_ASSERT(rv, prefix) \
+  {                           \
+    if ((rv) != 0) {          \
+      fprintf(                \
+          stderr,             \
+          "[%s:%d] %s: %s\n", \
+          __FILE__,           \
+          __LINE__,           \
+          prefix,             \
+          uv_strerror(rv));   \
