+
+  void run();
+
+ private:
+  static constexpr auto capacity_ = 64;
+
+  int fd_{-1};
+  std::atomic<bool> done_{false};
+  std::unique_ptr<std::thread> loop_;
+
+  std::mutex m_;
+  std::condition_variable cv_;
+};
