+
+size_t readResidentSetSize() {
+  std::stringstream path;
+  path << "/proc/" << getpid() << "/statm";
+  std::ifstream f(path.str());
+  size_t size;
+  size_t resident;
+  f >> size >> resident;
+  return (getpagesize() * resident);
