+  for (auto& fn : reorderFunctionArguments(&gloo::sum<TypeParam>)) {
+    for (auto i = 0; i < num; i++) {
+      for (auto j = 0; j < num; j++) {
+        a[j] = 1;
+        b[j] = 1;
+        c[j] = 0;
+      }
+      a[i] = 2;
+      fn(&c[0], &a[0], &b[0], num);
+      for (auto j = 0; j < num; j++) {
+        if (j == i) {
