+  std::array<TypeParam, 1000> a, b, c;
+  size_t n = 0;
+  auto start = std::chrono::system_clock::now();
+  std::chrono::nanoseconds duration;
+  for (;;) {
+    fn(&c[0], &a[0], &b[0], c.size());
+    n += c.size();
+    duration = std::chrono::system_clock::now() - start;
+    if (duration.count() >= 1000000) {
