+        }
+
+        broadcast(opts);
+
+        // Validate output
+        const auto ptr = output.getPointer();
+        const auto stride = context->size;
+        for (auto k = 0; k < dataSize; k++) {
+          ASSERT_EQ(root + k * stride, ptr[k])
