commit 5727866f0d9f9d1bbcd18943443486a900c97ed0
Author: Pieter Noordhuis <pietern@fb.com>
Date:   Tue Oct 9 21:38:57 2018 -0700

    Fix bug concerning remote pending send tally

    Summary:
    Every immediate recv call triggers a notification to be sent to the
    peer that is will be receving from. This is needed because all use of
    send and recv is unbuffered; i.e. the sender can only send when it
    knows the remote side is ready to receive.

    The remote send call checks if there is a remote pending receive, and
    if so, immediately sends its buffer. The bug here was that is did NOT
    send the accompanying notification that causes the remote pending send
    tally on the remote side of the pair to increase. The tally for remote
    pending sends is only used to trigger a check for local recv-from-any
    calls. If there is one, and the slot, and rank of the sending process
    match, the recv-from-any can be fulfilled by this send.

    With the tally not being updated correctly, the recv-from-any call
    could block forever waiting for a remote send, while one or more
    remote sends were in fact pending. Because of the incorrect tally (it
    being zero or negative), the check if such a send operation would
    match an existing recv-from-any did not execute.

    Reviewed By: romain-intel

    Differential Revision: D10243958

    fbshipit-source-id: a08c0dd48905958cac466737099ec7f45f6e0582
---
 gloo/test/send_recv_test.cc | 55 +++++++++++++++++++++++++++++++++++++++++++++
 gloo/transport/tcp/pair.cc  |  5 +++++
 2 files changed, 60 insertions(+)

diff --git a/gloo/test/send_recv_test.cc b/gloo/test/send_recv_test.cc
index 2feac3c..8f3348b 100644
--- a/gloo/test/send_recv_test.cc
+++ b/gloo/test/send_recv_test.cc
@@ -263,6 +263,61 @@ TEST_P(SendRecvTest, RecvFromAnyPipeline) {
     });
 }

+// This test stresses the pattern that is commonly used for some sort
+// of RPC on top of send/recv primitives. The server executes an
+// indirect recv (that can be fulfilled any some subset of peers) to
+// receive the message size and rank of a client, followed by an
+// immediate recv from that rank to get the actual message.
+TEST_P(SendRecvTest, RecvFromAnyRPC) {
+  auto contextSize = std::get<0>(GetParam());
+  spawn(contextSize, [&](std::shared_ptr<Context> context) {
+      constexpr uint64_t slot = 0x1337;
+      constexpr auto niters = 10;
+      size_t tmp0;
+      size_t tmp1;
+      auto buf0 = context->createUnboundBuffer(&tmp0, sizeof(tmp0));
+      auto buf1 = context->createUnboundBuffer(&tmp1, sizeof(tmp1));
+
+      if (context->rank == 0) {
+        // Keep number of recvs per rank
+        std::unordered_map<int, int> counts;
+        // Compile vector of ranks to receive from
+        std::vector<int> allRanks;
+        for (auto i = 0; i < context->size; i++) {
+          if (i == context->rank) {
+            continue;
+          }
+          allRanks.push_back(i);
+        }
+        // Receive twice from every peer, niters times
+        for (auto i = 0; i < (niters * (context->size - 1)); i++) {
+          int rank;
+          // Receive from any peer first
+          buf0->recv(allRanks, slot);
+          buf0->waitRecv(&rank);
+          counts[rank]++;
+          // Then receive from the same peer again
+          buf1->recv(rank, slot);
+          buf1->waitRecv();
+        }
+        // Verify result
+        for (auto i = 0; i < context->size; i++) {
+          if (i == context->rank) {
+            continue;
+          }
+          ASSERT_EQ(niters, counts[i]) << "recv mismatch for rank " << i;
+        }
+      } else {
+        for (auto i = 0; i < niters; i++) {
+          buf0->send(0, slot);
+          buf0->waitSend();
+          buf1->send(0, slot);
+          buf1->waitSend();
+        }
+      }
+    });
