+#ifdef DEBUG
+#define DEBUG_PRINT_STAGE(stage) \
+  do {                           \
+    printStageBuffer(stage);     \
+  } while (false)
+#define DEBUG_PRINT_SEND(stage)                                              \
+  do {                                                                       \
+    printStepBuffer(                                                         \
+        stage, step, myRank_, destRank, &scratch_[0], sendCount, ptrOffset); \
+  } while (false)
+#define DEBUG_PRINT_RECV(stage)              \
