+    printStepBuffer(                         \
+        stage,                               \
+        step,                                \
+        srcRank,                             \
+        myRank_,                             \
+        &recvBufs_[recvBufIdx_[srcRank]][0], \
+        recvCount);                          \
+  } while (false)
+#else
+#define DEBUG_PRINT_STAGE(stage)
+#define DEBUG_PRINT_SEND(stage)
+#define DEBUG_PRINT_RECV(stage)
+#endif
