+class Barrier {
+ public:
+  explicit Barrier(std::size_t count) : count_(count) {}
+
+  void wait() {
+    std::unique_lock<std::mutex> lock(mutex_);
+    if (count_ > 0) {
+      if (--count_ == 0) {
+        cv_.notify_all();
+      } else {
+        cv_.wait(lock, [this] { return count_ == 0; });
+      }
+    }
+  }
+
+ private:
+  std::size_t count_;
+  std::mutex mutex_;
+  std::condition_variable cv_;
+};
