     spawnThreads(size, [&](int rank) {
         auto context =
           std::make_shared<::gloo::rendezvous::Context>(rank, size);
         if (size > 1) {
           context->connectFullMesh(*store_, device_);
         }
-        fn(std::move(context));
+        fn(context);
