commit 2a282836808537d99253cfed65de78b6d6b506dc
Author: Pieter Noordhuis <pietern@fb.com>
Date:   Mon May 1 12:24:34 2017 -0700

    Fix pair destructor if in CONNECTING state

    Summary:
    It can happen that a pair is destructed while in CONNECTING
    state when some unrelated code throws an exception after the connect
    function has been called. The most likely place for this to happen is
    when connecting pair A is in progress while connecting pair B throws
    an exception. The exception will force destruction of all references
    to pair A, even if it is in the CONNECTING state.

    Also see https://github.com/facebookincubator/gloo/issues/33

    Reviewed By: andrewwdye

    Differential Revision: D4979557

    fbshipit-source-id: 0cddddd3f478106f1694603fe7f2efe15a2d9aa1
---
 gloo/transport/tcp/pair.cc | 15 +++++++++------
 1 file changed, 9 insertions(+), 6 deletions(-)

diff --git a/gloo/transport/tcp/pair.cc b/gloo/transport/tcp/pair.cc
index e1ad254..fc632cd 100644
--- a/gloo/transport/tcp/pair.cc
+++ b/gloo/transport/tcp/pair.cc
@@ -578,18 +578,21 @@ void Pair::changeState(state nextState) {
       close(fd_);
       fd_ = FD_INVALID;
     } else if (state_ == LISTENING) {
-      // The pair may be in the LISTENING state when it is destructed,
-      // for example when the pair was created but left unused.
+      // The pair may be in the LISTENING state when it is destructed.
+      if (fd_ != FD_INVALID) {
+        dev_->unregisterDescriptor(fd_);
+        close(fd_);
+        fd_ = FD_INVALID;
+      }
+    } else if (state_ == CONNECTING) {
+      // The pair may be in the CONNECTING state when it is destructed.
       if (fd_ != FD_INVALID) {
         dev_->unregisterDescriptor(fd_);
         close(fd_);
         fd_ = FD_INVALID;
       }
     } else {
-      // The CONNECTING states ensures the file descriptor is
-      // unregistered and closed before throwing exceptions that may result in
-      // destruction of the pair.
-      GLOO_ENFORCE_EQ(fd_, FD_INVALID, "File descriptor not closed");
+      GLOO_ENFORCE(false, "Invalid state: ", state_);
     }
   }

