+class CudaAllreduceHalvingDoubling : public Algorithm {
+ public:
+  CudaAllreduceHalvingDoubling(
+      const std::shared_ptr<Context>& context,
+      const std::vector<T*>& ptrs,
+      const int count,
+      const std::vector<cudaStream_t>& streams  = std::vector<cudaStream_t>());
+
